ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name WHERE {
  ?p a :Projects .
  ?f a :Field_Of_Study .
  ?p p:hasField_Of_Study ?f .
  ?f p:name ?name .
  ?p p:title ?title_f .
  FILTER(STR(?title_f) = "Quantum Mechanics Experiment")
} }
  component_2: { SELECT ?name WHERE {
  ?p a :Projects .
  ?f a :Topics .
  ?p p:hasTopic ?f .
  ?f p:name ?name .
  ?p p:title ?title_f .
  FILTER(STR(?title_f) = "Quantum Mechanics Experiment")
} }
  full: { SELECT ?name ?name2 WHERE {
  ?p a :Projects .
  ?f a :Topics .
  ?p p:hasTopic ?f .
  ?fs a :Field_Of_Study .
  ?p p:hasField_Of_Study ?fs .
  ?f p:name ?name .
  ?fs p:name ?name2 .
  ?p p:title ?title_f .
  FILTER(STR(?title_f) = "Quantum Mechanics Experiment")
} }
}
